#include <stdio.h>
#include <stdlib.h>
#include <string.h>

int cmpInt(const void *a, const void *b) {
    int x = *(const int *)a;
    int y = *(const int *)b;
    return (x > y) - (x < y);
}

int parseLine(char *line, int **arr) {
    int *tmp = NULL;
    int cnt = 0;
    char *p = strchr(line, '[');
    if (!p) return 0;
    p++;
    while (*p && *p != ']') {
        while (*p == ' ' || *p == ',') p++;
        if (*p == ']' || *p == '\0') break;
        int val = strtol(p, &p, 10);
        tmp = realloc(tmp, (cnt + 1) * sizeof(int));
        tmp[cnt++] = val;
        while (*p == ' ' || *p == ',') p++;
    }
    *arr = tmp;
    return cnt;
}

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    char buffer[200000];
    fgets(buffer, sizeof(buffer), stdin); // consume endline after T
    for (int tc = 0; tc < T; ++tc) {
        if (!fgets(buffer, sizeof(buffer), stdin)) break;
        int *children = NULL;
        int n = parseLine(buffer, &children);
        if (!fgets(buffer, sizeof(buffer), stdin)) break;
        int *cookies = NULL;
        int m = parseLine(buffer, &cookies);
        qsort(children, n, sizeof(int), cmpInt);
        qsort(cookies, m, sizeof(int), cmpInt);
        int i = 0, j = 0, ans = 0;
        while (i < n && j < m) {
            if (cookies[j] >= children[i]) {
                ++ans; ++i; ++j;
            } else {
                ++j;
            }
        }
        printf("%d\n", ans);
        free(children);
        free(cookies);
    }
    return 0;
}

