#include <bits/stdc++.h>
using namespace std;

vector<int> parseLine(const string &s) {
    vector<int> res;
    size_t i = s.find('[');
    if (i == string::npos) return res;
    ++i;
    while (i < s.size() && s[i] != ']') {
        while (i < s.size() && (s[i] == ' ' || s[i] == ',')) ++i;
        if (i >= s.size() || s[i] == ']') break;
        bool neg = false;
        if (s[i] == '-') { neg = true; ++i; }
        int val = 0;
        while (i < s.size() && isdigit(s[i])) {
            val = val * 10 + (s[i] - '0');
            ++i;
        }
        if (neg) val = -val;
        res.push_back(val);
        while (i < s.size() && (s[i] == ' ' || s[i] == ',')) ++i;
    }
    return res;
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T;
    if (!(cin >> T)) return 0;
    string line;
    getline(cin, line); // consume endline after T
    for (int tc = 0; tc < T; ++tc) {
        getline(cin, line);
        vector<int> children = parseLine(line);
        getline(cin, line);
        vector<int> cookies = parseLine(line);
        sort(children.begin(), children.end());
        sort(cookies.begin(), cookies.end());
