        while (i < (int)children.size() && j < (int)cookies.size()) {
            if (cookies[j] >= children[i]) {
                ++ans; ++i; ++j;
            } else {
                ++j;
            }
        }
        cout << ans << '\n';
    }
    return 0;
}

