import java.io.*;
import java.util.*;

public class Main {
    private static List<Integer> parseLine(String s) {
        List<Integer> list = new ArrayList<>();
        int i = s.indexOf('[');
        if (i == -1) return list;
        i++;
        while (i < s.length() && s.charAt(i) != ']') {
            char c = s.charAt(i);
            if (c == ',' || c == ' ') { i++; continue; }
            int sign = 1;
            if (c == '-') { sign = -1; i++; }
            int val = 0;
            while (i < s.length() && Character.isDigit(s.charAt(i))) {
                val = val * 10 + (s.charAt(i) - '0');
                i++;
            }
            list.add(sign * val);
        }
        return list;
    }

    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        String line = br.readLine();
        if (line == null) return;
        int T = Integer.parseInt(line.trim());
        for (int tc = 0; tc < T; ++tc) {
            String childLine = br.readLine();
            String cookieLine = br.readLine();
            List<Integer> childList = parseLine(childLine);
            List<Integer> cookieList = parseLine(cookieLine);
            int[] children = childList.stream().mapToInt(Integer::intValue).toArray();
            int[] cookies = cookieList.stream().mapToInt(Integer::intValue).toArray();
            Arrays.sort(children);
            Arrays.sort(cookies);
            int i = 0, j = 0, ans = 0;
            while (i < children.length && j < cookies.length) {
                if (cookies[j] >= children[i]) {
                    ans++; i++; j++;
                } else {
                    j++;
                }
            }
            System.out.println(ans);
        }
    }
}

