import sys, re

def parse_line(line: str):
    return list(map(int, re.findall(r'-?\d+', line)))

def main():
    data = sys.stdin.read().splitlines()
    if not data:
        return
    t = int(data[0].strip())
    idx = 1
    out = []
    for _ in range(t):
        children = parse_line(data[idx])
        idx += 1
        cookies = parse_line(data[idx])
        idx += 1
        children.sort()
        cookies.sort()
        i = j = cnt = 0
        while i < len(children) and j < len(cookies):
            if cookies[j] >= children[i]:
                cnt += 1
                i += 1
                j += 1
            else:
                j += 1
        out.append(str(cnt))
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    main()

